import React, { useContext } from 'react';
import { View, Text, StyleSheet, TouchableOpacity } from 'react-native';
import { useNavigation } from '@react-navigation/native';
import { AppContext } from '../../App';

const steps = [
  { key: 'ownership_screen', label: 'Propriétaire' },
  { key: 'vehicle_owner_form_screen', label: 'Identité' },
  { key: 'not_vehicle_owner_form_screen', label: 'Informations' },
  { key: 'find_immatriculation_or_chasis_number_screen', label: 'Immatriculation' },
  { key: 'car_registration_doc_upload', label: 'Carte Grise' },
  { key: 'public_transport_doc_upload', label: 'Carte Transport' },
  { key: 'tax_payment_receipt_doc_upload', label: 'Reçu Impôts' },
  { key: 'transport_licence_doc_upload', label: 'Licence' },
  { key: 'document_upload_completion_screen', label: 'Terminé' },
];

export default function FormProgressTracker() {
  const { formProgress, verification } = useContext(AppContext);
  const navigation = useNavigation();

  const handleStepPress = (stepKey) => {
    // Only allow navigation to completed steps or next step
    if (formProgress.completedSteps.includes(stepKey) || 
        stepKey === formProgress.currentStep) {
      navigation.navigate(stepKey);
    }
  };

  return (
    <View style={styles.container}>
      <View style={styles.stepsContainer}>
        {steps.map((step, index) => {
          const isCompleted = formProgress.completedSteps.includes(step.key);
          const isCurrent = formProgress.currentStep === step.key;
          const isDisabled = !isCompleted && !isCurrent;

          return (
            <React.Fragment key={step.key}>
              <TouchableOpacity
                style={[
                  styles.step,
                  isCompleted && styles.stepCompleted,
                  isCurrent && styles.stepCurrent,
                  isDisabled && styles.stepDisabled,
                ]}
                onPress={() => handleStepPress(step.key)}
                disabled={isDisabled}
              >
                <Text style={[
                  styles.stepText,
                  isCompleted && styles.stepTextCompleted,
                  isCurrent && styles.stepTextCurrent,
                  isDisabled && styles.stepTextDisabled,
                ]}>
                  {index + 1}
                </Text>
              </TouchableOpacity>

              {index < steps.length - 1 && (
                <View style={[
                  styles.line,
                  isCompleted && styles.lineCompleted,
                ]} />
              )}
            </React.Fragment>
          );
        })}
      </View>

      <Text style={styles.currentStepLabel}>
        {steps.find(s => s.key === formProgress.currentStep)?.label || 'Démarrage'}
      </Text>
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    padding: 16,
    backgroundColor: '#fff',
    borderBottomWidth: 1,
    borderBottomColor: '#e0e0e0',
  },
  stepsContainer: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'center',
    marginBottom: 8,
  },
  step: {
    width: 32,
    height: 32,
    borderRadius: 16,
    backgroundColor: '#e0e0e0',
    alignItems: 'center',
    justifyContent: 'center',
  },
  stepCompleted: {
    backgroundColor: '#4CAF50',
  },
  stepCurrent: {
    backgroundColor: '#2196F3',
    borderWidth: 2,
    borderColor: '#1976D2',
  },
  stepDisabled: {
    opacity: 0.5,
  },
  stepText: {
    color: '#757575',
    fontWeight: 'bold',
  },
  stepTextCompleted: {
    color: '#fff',
  },
  stepTextCurrent: {
    color: '#fff',
  },
  stepTextDisabled: {
    color: '#9e9e9e',
  },
  line: {
    flex: 1,
    height: 2,
    backgroundColor: '#e0e0e0',
    marginHorizontal: 8,
  },
  lineCompleted: {
    backgroundColor: '#4CAF50',
  },
  currentStepLabel: {
    textAlign: 'center',
    fontSize: 14,
    fontWeight: '600',
    color: '#333',
  },
});
